// Mock scene registry for Phase IV viewport fixtures. Instead of
// bringing up the real Spark / three.js renderer inside a fixture,
// fixtures reference a pre-captured static PNG of the viewport canvas
// and the real-app DOM overlays (gizmos, render-box, drop-hint, etc.)
// mount live on top. Backdrop PNGs live in
// `docs/help/assets/fixture-backdrops/` and are regenerated by running
// `preview_eval captureBackdrop(id)` from a loaded cf-test2 session.
//
// Each scene record carries the natural canvas dimensions so fixtures
// can size the placeholder element correctly when they embed it.

/**
 * @typedef {object} MockSceneRecord
 * @property {string} id             Identifier used by makeScene().
 * @property {string} backdropUrl    Path to the static PNG relative to
 *                                   the docs page root.
 * @property {number} width          Natural canvas width in pixels.
 * @property {number} height         Natural canvas height in pixels.
 * @property {string} [description]  Human-readable note.
 */

/** @type {Record<string, MockSceneRecord>} */
const SCENES = {
	"cf-test2-default": {
		id: "cf-test2-default",
		backdropUrl: "/docs/help/assets/fixture-backdrops/cf-test2-default.png",
		width: 1073,
		height: 1264,
		description:
			"cf-test2 の仮のシーン（権利クリア済みの motorbike スプラット）",
	},
};

/**
 * Look up a named mock scene. Throws on unknown id so fixtures surface
 * the typo at render time instead of rendering a broken placeholder.
 *
 * @param {string} id
 * @returns {MockSceneRecord}
 */
export function makeScene(id) {
	const record = SCENES[id];
	if (!record) {
		throw new Error(`makeScene: unknown scene "${id}"`);
	}
	return record;
}

/** @returns {MockSceneRecord[]} */
export function listScenes() {
	return Object.values(SCENES);
}
